const headers=$('Webhook Calc').first().json.headers||{};const body=$('Webhook Calc').first().json.body||{};
const token=(headers.authorization||headers.Authorization||'').replace('Bearer ','');
if(!token) return [{json:{error:true,message:'Thiếu token',status:401}}];
let userId;try{userId=JSON.parse(Buffer.from(token.split('.')[1],'base64').toString()).sub;if(!userId)throw 0;}catch(e){return [{json:{error:true,message:'Token không hợp lệ',status:401}}];}
if(!body.formula_code) return [{json:{error:true,message:'Thiếu formula_code',status:400}}];
if(!/^[A-Za-z0-9\-_\.]{1,50}$/.test(body.formula_code)) return [{json:{error:true,message:'formula_code không hợp lệ (chỉ A-Z, a-z, 0-9, -, _, .)',status:400}}];
if(!body.input_data) return [{json:{error:true,message:'Thiếu input_data',status:400}}];
return [{json:{error:false,user_id:userId,formula_code:body.formula_code,input_data:body.input_data,job_name:body.job_name||'',acceptance_criteria:body.acceptance_criteria||null}}];

// ========================================
// Chạy tính toán DETERMINISTIC (không AI)
// ========================================
const results=$input.all().map(i=>i.json);
const prev=$('Parse + Auth').first().json;
const formula=results.find(r=>r.formula_code);
const prompt=results.find(r=>r.prompt_text);

if(!formula) return [{json:{error:true,message:'Không tìm thấy công thức: '+prev.formula_code,status:404}}];

// Parse input data
const inputData=typeof prev.input_data==='string'?JSON.parse(prev.input_data):prev.input_data;

// Chạy công thức bằng JavaScript (deterministic)
let calcResult=null;
let calcError=null;
let steps=[];

try {
  // Tạo variables từ input_data
  const vars={};
  for(const[k,v]of Object.entries(inputData)) vars[k]=v;

  // Thêm tất cả input vars vào scope
  const fn=new Function(...Object.keys(vars),'return '+formula.formula_js);
  calcResult=fn(...Object.values(vars));

  steps.push({step:'Input',detail:JSON.stringify(inputData)});
  steps.push({step:'Công thức',detail:formula.formula_display});
  steps.push({step:'JS expression',detail:formula.formula_js});
  steps.push({step:'Kết quả',detail:String(calcResult)});
} catch(e) {
  calcError='Lỗi tính toán: '+e.message;
}

if(calcError) return [{json:{error:true,message:calcError,status:500}}];

// Đánh giá pass/fail nếu có criteria
let passFail='no_criteria';
let criteriaNote='';
if(prev.acceptance_criteria){
  const ac=typeof prev.acceptance_criteria==='string'?JSON.parse(prev.acceptance_criteria):prev.acceptance_criteria;
  if(ac.operator==='<='&&calcResult<=ac.value) passFail='pass';
  else if(ac.operator==='>='&&calcResult>=ac.value) passFail='pass';
  else if(ac.operator==='<'&&calcResult<ac.value) passFail='pass';
  else if(ac.operator==='>'&&calcResult>ac.value) passFail='pass';
  else if(ac.operator==='=='&&calcResult==ac.value) passFail='pass';
  else passFail='fail';
  criteriaNote=`Tiêu chí: ${ac.operator} ${ac.value} ${ac.unit||''} (Nguồn: ${ac.source||'N/A'})`;
}

// Build AI interpretation request
const messages=[{role:'system',content:prompt?.prompt_text||'Diễn giải kết quả tính toán GMP bằng tiếng Việt.'},{role:'user',content:`Công thức: ${formula.formula_name} (${formula.formula_code} v${formula.version})\nHiển thị: ${formula.formula_display}\nNguồn: ${formula.reference_source||'N/A'}\n\nInput: ${JSON.stringify(inputData)}\nKết quả: ${calcResult}\n${criteriaNote?'\n'+criteriaNote+'\nKết luận: '+(passFail==='pass'?'ĐẠT':passFail==='fail'?'KHÔNG ĐẠT':'Chưa có tiêu chí'):'\nChưa có tiêu chí chấp nhận đã phê duyệt.'}\n\nHãy diễn giải kết quả này bằng tiếng Việt.`}];

return [{json:{...prev,formula_name:formula.formula_name,formula_version:formula.version,formula_display:formula.formula_display,reference_source:formula.reference_source,calcResult,steps,passFail,criteriaNote,messages}}];

const ai=$input.first().json;
const prev=$('Run Calculation + Build AI').first().json;
const interpretation=ai.choices?.[0]?.message?.content||'Không diễn giải được.';

const sql=`INSERT INTO calculation_jobs(user_id,formula_code,formula_version,job_name,status,input_data,result_data,intermediate_steps,interpretation,acceptance_criteria,pass_fail,model_used) VALUES('${prev.user_id}'::uuid,'${prev.formula_code}','${prev.formula_version}','${(prev.job_name||'').replace(/'/g,"''")}','completed','${JSON.stringify(prev.input_data).replace(/'/g,"''")}'::jsonb,'{"result":${prev.calcResult}}'::jsonb,'${JSON.stringify(prev.steps).replace(/'/g,"''")}'::jsonb,'${interpretation.replace(/'/g,"''")}',${prev.acceptance_criteria?"'"+JSON.stringify(prev.acceptance_criteria).replace(/'/g,"''")+"'::jsonb":'NULL'},'${prev.passFail}','gpt-4o-mini') RETURNING id;\nSELECT write_audit_log('${prev.user_id}'::uuid,NULL,NULL,'ai_calculate'::audit_action,'Calc ${prev.formula_code}: ${prev.calcResult}');`;

return [{json:{sql,response:{success:true,formula:prev.formula_name,formula_code:prev.formula_code,formula_version:prev.formula_version,formula_display:prev.formula_display,reference_source:prev.reference_source,input:prev.input_data,result:prev.calcResult,steps:prev.steps,pass_fail:prev.passFail,criteria_note:prev.criteriaNote,interpretation,disclaimer:'⚕ Diễn giải do AI thực hiện. Cần người có chuyên môn xác nhận trước khi đưa vào hồ sơ GMP.'}}}];
